"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import type { IconSvgElement } from "@hugeicons/react"

/* ── Types ── */

export interface ComposerTask {
  label: string
  done: boolean
  dimmed?: boolean
}

export interface ComposerFile {
  name: string
  size: string
  type: "file" | "image"
}

export interface ComposerScopeItem {
  id: string
  label: string
  icon: IconSvgElement
}

/* ── Context ── */

export interface ComposerState {
  value: string
  isFocused: boolean
  isSending: boolean
  disabled: boolean
  canSend: boolean
}

export interface ComposerActions {
  setValue: (value: string) => void
  setFocused: (focused: boolean) => void
  send: () => void
}

export interface ComposerMeta {
  textareaRef: React.RefObject<HTMLTextAreaElement | null>
}

export interface ComposerContextValue {
  state: ComposerState
  actions: ComposerActions
  meta: ComposerMeta
}

export const ComposerContext = React.createContext<ComposerContextValue | null>(
  null
)

export function useComposer(): ComposerContextValue {
  const ctx = React.use(ComposerContext)
  if (!ctx) {
    throw new Error("useComposer must be used within a <ComposerProvider />")
  }
  return ctx
}

/* ── ComposerProvider ── */

export function ComposerProvider({
  state,
  actions,
  meta,
  children,
}: {
  state: ComposerState
  actions: ComposerActions
  meta: ComposerMeta
  children: React.ReactNode
}) {
  const ctx = React.useMemo<ComposerContextValue>(
    () => ({ state, actions, meta }),
    [state, actions, meta]
  )

  return <ComposerContext value={ctx}>{children}</ComposerContext>
}

/* ── ComposerFrame ── */

export function ComposerFrame({
  className,
  children,
  onSubmit,
  ...props
}: React.ComponentProps<"form">) {
  const {
    actions: { send },
  } = useComposer()

  return (
    <form
      data-slot="composer"
      onSubmit={(event) => {
        event.preventDefault()
        onSubmit?.(event)
        send()
      }}
      className={cn(
        "mx-auto flex w-full max-w-[720px] flex-col items-center",
        className
      )}
      {...props}
    >
      {children}
    </form>
  )
}

/* ── Composer (local-state convenience root) ── */

export function Composer({
  value: valueProp,
  defaultValue = "",
  onValueChange: onValueChangeProp,
  onSend,
  canSend: canSendProp,
  disabled = false,
  className,
  children,
  ...props
}: Omit<React.ComponentProps<"form">, "onSubmit" | "onChange"> & {
  value?: string
  defaultValue?: string
  onValueChange?: (value: string) => void
  onSend?: (value: string) => void
  canSend?: boolean
  disabled?: boolean
}) {
  const [_value, _setValue] = React.useState(defaultValue)
  const value = valueProp ?? _value
  const setValue = React.useCallback(
    (v: string) => {
      if (onValueChangeProp) onValueChangeProp(v)
      else _setValue(v)
    },
    [onValueChangeProp]
  )

  const [isFocused, setIsFocused] = React.useState(false)
  const [isSending, setIsSending] = React.useState(false)
  const textareaRef = React.useRef<HTMLTextAreaElement | null>(null)
  const canSend = canSendProp ?? value.trim().length > 0

  const send = React.useCallback(() => {
    if (disabled) return
    if (!canSend) return
    setIsSending(true)
    const currentValue = value
    setTimeout(() => {
      setValue("")
      setIsSending(false)
      if (textareaRef.current) textareaRef.current.style.height = "auto"
    }, 400)
    onSend?.(currentValue)
  }, [value, disabled, canSend, setValue, onSend])

  const state = React.useMemo<ComposerState>(
    () => ({
      value,
      isFocused,
      isSending,
      disabled,
      canSend,
    }),
    [value, isFocused, isSending, disabled, canSend]
  )

  const actions = React.useMemo<ComposerActions>(
    () => ({
      setValue,
      setFocused: setIsFocused,
      send,
    }),
    [setValue, send]
  )

  const meta = React.useMemo<ComposerMeta>(
    () => ({ textareaRef }),
    [textareaRef]
  )

  return (
    <ComposerProvider state={state} actions={actions} meta={meta}>
      <ComposerFrame className={className} {...props}>
        {children}
      </ComposerFrame>
    </ComposerProvider>
  )
}

/* ── ComposerIslands ── */

export function ComposerIslands({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-islands"
      className={cn(
        "flex w-full flex-col items-center",
        "[&>[data-slot=composer-island-wrap]:first-child>[data-slot=composer-island]]:rounded-t-lg sm:[&>[data-slot=composer-island-wrap]:first-child>[data-slot=composer-island]]:rounded-t-xl [&>[data-slot=composer-island-wrap]:first-child>[data-slot=composer-island]]:shadow-[0_-1px_6px_rgba(0,0,0,0.04),0_-4px_16px_rgba(0,0,0,0.03)]",
        "[&>[data-slot=composer-island-wrap]:not(:first-child)>[data-slot=composer-island]]:rounded-t-none [&>[data-slot=composer-island-wrap]:not(:first-child)>[data-slot=composer-island]]:border-t-0",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerCard ── */

export function ComposerCard({
  className,
  children,
  onMouseDown,
  ...props
}: React.ComponentProps<"div">) {
  const {
    state: { isFocused },
    meta: { textareaRef },
  } = useComposer()

  return (
    <div
      data-slot="composer-card"
      onMouseDown={(event) => {
        onMouseDown?.(event)
        if (event.defaultPrevented) return
        const target = event.target
        if (!(target instanceof HTMLElement)) return
        if (
          target.closest(
            "button,a,input,textarea,select,[role=button],[data-no-focus]"
          )
        ) {
          return
        }
        textareaRef.current?.focus()
      }}
      className={cn(
        "relative z-1 w-full rounded-lg border bg-background transition-shadow duration-300 ease-out sm:rounded-xl",
        isFocused
          ? "border-foreground/15 shadow-[0_0_0_1px_rgba(0,0,0,0.03),0_2px_12px_rgba(0,0,0,0.06),0_8px_32px_rgba(0,0,0,0.04)]"
          : "border-border shadow-[0_1px_3px_rgba(0,0,0,0.04),0_4px_16px_rgba(0,0,0,0.03)]",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── Re-exports ── */

export { ComposerInput } from "./composer-input"
export {
  ComposerToolbar,
  ComposerMenu,
  ComposerContextRing,
  ComposerSend,
} from "./composer-toolbar"
export { ComposerScope, ComposerReply, ComposerPlan } from "./composer-islands"
export { ComposerAttachments } from "./composer-attachments"
export { ComposerSuggestions } from "./composer-suggestions"

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"
import { Textarea } from "./textarea"

export function ComposerInput({
  placeholder = "Type a message…",
  maxHeight = 160,
  className,
  "aria-label": ariaLabel,
  name = "message",
  autoComplete = "off",
  ...props
}: Omit<React.ComponentProps<"textarea">, "value" | "onChange"> & {
  maxHeight?: number
}) {
  const {
    state,
    actions: { setValue, setFocused, send },
    meta: { textareaRef },
  } = useComposer()

  React.useEffect(() => {
    const ta = textareaRef.current
    if (!ta) return
    ta.style.height = "auto"
    ta.style.height = Math.min(ta.scrollHeight, maxHeight) + "px"
  }, [state.value, maxHeight, textareaRef])

  return (
    <div
      data-slot="composer-input"
      className={cn("px-2 pt-0.5 pb-0 sm:px-4 sm:pt-3 sm:pb-1", className)}
    >
      <Textarea
        data-compact-touch
        ref={textareaRef}
        value={state.value}
        onChange={(e) => setValue(e.target.value)}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        onKeyDown={(e) => {
          if (e.key === "Enter" && !e.shiftKey) {
            e.preventDefault()
            send()
          }
        }}
        placeholder={placeholder}
        aria-label={ariaLabel ?? "Message"}
        name={name}
        autoComplete={autoComplete}
        disabled={state.disabled}
        rows={1}
        className="max-h-[160px] min-h-6 resize-none rounded-none border-0 bg-transparent px-0 py-0 text-base leading-5 shadow-none placeholder:text-[12px] placeholder:leading-4 placeholder:text-muted-foreground/50 focus-visible:ring-0 sm:leading-6 sm:placeholder:text-sm md:text-sm dark:bg-transparent"
        style={{ maxHeight }}
        {...props}
      />
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import { ArrowUp02Icon, Add01Icon } from "@hugeicons/core-free-icons"
import {
  DropdownMenu,
  DropdownMenuTrigger,
  DropdownMenuContent,
} from "@/components/ui/dropdown-menu"
import {
  Tooltip,
  TooltipContent,
  TooltipTrigger,
} from "@/components/ui/tooltip"
import { useComposer } from "./composer"

/* ── ComposerToolbar ── */

export function ComposerToolbar({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-toolbar"
      className={cn(
        "flex items-center gap-1 px-1.5 pt-0 pb-0.5 sm:px-3 sm:pt-0.5 sm:pb-3",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

/* ── ComposerMenu ── */

export function ComposerMenu({
  className,
  children,
}: {
  children: React.ReactNode
  className?: string
}) {
  return (
    <DropdownMenu>
      <DropdownMenuTrigger
        data-compact-touch
        data-slot="composer-menu-trigger"
        aria-label="Open composer menu"
        className={cn(
          "flex size-7 items-center justify-center rounded-md text-muted-foreground/50 transition-colors duration-200 outline-none hover:bg-muted/60 hover:text-foreground",
          className
        )}
      >
        <HugeiconsIcon icon={Add01Icon} size={16} strokeWidth={1.5} />
      </DropdownMenuTrigger>
      <DropdownMenuContent
        side="top"
        sideOffset={8}
        align="start"
        className="min-w-[200px]"
      >
        {children}
      </DropdownMenuContent>
    </DropdownMenu>
  )
}

/* ── ComposerContextRing ── */

export function ComposerContextRing({
  used,
  total,
  label,
  className,
  ...props
}: React.ComponentProps<"button"> & {
  used: number
  total: number
  label?: string
}) {
  const pct = total > 0 ? used / total : 0
  const r = 6
  const circ = 2 * Math.PI * r
  const offset = circ * (1 - pct)
  const displayLabel = label ?? `${used}k / ${total}k tokens`
  const pctLabel = `${Math.round(pct * 100)}%`

  return (
    <Tooltip>
      <TooltipTrigger
        render={
          <button
            type="button"
            data-compact-touch
            data-slot="composer-context-ring"
            aria-label={`${displayLabel}, ${pctLabel} used`}
            className={cn(
              "mr-1 flex size-7 items-center justify-center rounded-md text-muted-foreground/70 transition-colors hover:bg-muted/60 hover:text-foreground focus-visible:ring-3 focus-visible:ring-ring/50 focus-visible:outline-none",
              className
            )}
            {...props}
          />
        }
      >
        <svg width="16" height="16" viewBox="0 0 16 16" className="opacity-70">
          <circle
            cx="8"
            cy="8"
            r={r}
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            opacity="0.15"
          />
          <circle
            cx="8"
            cy="8"
            r={r}
            fill="none"
            stroke="currentColor"
            strokeWidth="1.5"
            strokeDasharray={circ}
            strokeDashoffset={offset}
            strokeLinecap="round"
            transform="rotate(-90 8 8)"
          />
        </svg>
      </TooltipTrigger>
      <TooltipContent side="top" sideOffset={8}>
        {displayLabel} ({pctLabel})
      </TooltipContent>
    </Tooltip>
  )
}

/* ── ComposerSend ── */

export function ComposerSend({
  className,
  ...props
}: React.ComponentProps<"button">) {
  const { state } = useComposer()
  const [arrowAnim, setArrowAnim] = React.useState(false)

  const handleClick = React.useCallback(() => {
    setArrowAnim(true)
    setTimeout(() => setArrowAnim(false), 500)
  }, [])

  return (
    <button
      data-compact-touch
      data-slot="composer-send"
      type="submit"
      onClick={handleClick}
      disabled={!state.canSend}
      aria-label={state.canSend ? "Send message" : "Send message unavailable"}
      className={cn(
        "flex size-7 items-center justify-center rounded-md transition-[opacity,transform] duration-200 focus-visible:ring-3 focus-visible:ring-ring/50 focus-visible:outline-none",
        state.canSend ? "hover:opacity-90" : "cursor-not-allowed",
        state.isSending ? "animate-composer-send" : "",
        className
      )}
      {...props}
    >
      <span
        className={cn(
          "flex size-6 items-center justify-center rounded-full transition-[color,background-color]",
          state.canSend
            ? "bg-foreground text-background"
            : "bg-muted/60 text-muted-foreground/40",
          arrowAnim ? "animate-composer-arrow" : ""
        )}
      >
        <HugeiconsIcon icon={ArrowUp02Icon} size={13} strokeWidth={2} />
      </span>
    </button>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import {
  Cancel01Icon,
  MailReply01Icon,
  Task01Icon,
  ArrowExpand01Icon,
  ArrowShrink01Icon,
} from "@hugeicons/core-free-icons"
import type { ComposerScopeItem } from "./composer"
import type { ComposerTask } from "./composer"

/* ── Island wrapper (used by each island primitive) ── */

function Island({
  className,
  children,
  ...props
}: React.ComponentProps<"div">) {
  return (
    <div
      data-slot="composer-island-wrap"
      className={cn("animate-composer-island w-full", className)}
      style={{ zIndex: 0 }}
      {...props}
    >
      <div
        data-slot="composer-island"
        className="border border-b-0 border-border bg-background"
      >
        {children}
      </div>
    </div>
  )
}

/* ── ComposerScope ── */

export function ComposerScope({
  items,
  onRemove,
  onDismiss,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  items: ComposerScopeItem[]
  onRemove?: (id: string) => void
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-2 px-2 py-1.5 sm:px-3 sm:py-2.5">
        <div className="flex min-w-0 flex-1 flex-wrap items-center gap-1.5">
          {items.map((item) => (
            <span
              key={item.id}
              className="animate-composer-slide group/scope inline-flex items-center gap-1.5 rounded-md border border-border bg-muted/40 px-1.5 py-0.5 text-[11px] leading-4 text-foreground sm:px-2 sm:text-xs"
            >
              <HugeiconsIcon
                icon={item.icon}
                size={12}
                strokeWidth={1.5}
                className="shrink-0 text-muted-foreground"
              />
              <span className="max-w-[160px] truncate">{item.label}</span>
              {onRemove && (
                <button
                  type="button"
                  onClick={() => onRemove(item.id)}
                  aria-label={`Remove ${item.label}`}
                  className="text-muted-foreground/50 transition-colors hover:text-foreground sm:opacity-0 sm:group-focus-within/scope:opacity-100 sm:group-hover/scope:opacity-100"
                >
                  <HugeiconsIcon
                    icon={Cancel01Icon}
                    size={10}
                    strokeWidth={2}
                  />
                </button>
              )}
            </span>
          ))}
        </div>
        {onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            aria-label="Dismiss scope"
            className="shrink-0 text-muted-foreground/40 transition-colors hover:text-foreground"
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </button>
        )}
      </div>
    </Island>
  )
}

/* ── ComposerReply ── */

export function ComposerReply({
  onDismiss,
  className,
  children,
  ...props
}: React.ComponentProps<"div"> & {
  onDismiss?: () => void
}) {
  return (
    <Island className={className} {...props}>
      <div className="flex items-center gap-2 px-2.5 py-1.5 sm:px-4 sm:py-2.5">
        <HugeiconsIcon
          icon={MailReply01Icon}
          size={13}
          strokeWidth={1.5}
          className="shrink-0 text-muted-foreground/60"
        />
        <span className="flex-1 truncate text-xs text-muted-foreground">
          {children}
        </span>
        {onDismiss && (
          <button
            type="button"
            onClick={onDismiss}
            aria-label="Dismiss reply context"
            className="shrink-0 text-muted-foreground/60 transition-colors hover:text-foreground"
          >
            <HugeiconsIcon icon={Cancel01Icon} size={14} strokeWidth={1.5} />
          </button>
        )}
      </div>
    </Island>
  )
}

/* ── ComposerPlan ── */

export function ComposerPlan({
  tasks,
  defaultExpanded = false,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  tasks: ComposerTask[]
  defaultExpanded?: boolean
}) {
  const [expanded, setExpanded] = React.useState(defaultExpanded)
  const completedCount = tasks.filter((t) => t.done).length

  return (
    <Island className={className} {...props}>
      <div className="px-2.5 py-1.5 sm:px-4 sm:py-3">
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2 text-xs text-muted-foreground">
            <HugeiconsIcon icon={Task01Icon} size={13} strokeWidth={1.5} />
            <span>
              {completedCount} out of {tasks.length} tasks completed
            </span>
          </div>
          <button
            type="button"
            data-compact-touch
            onClick={() => setExpanded(!expanded)}
            aria-label={expanded ? "Collapse plan" : "Expand plan"}
            aria-expanded={expanded}
            className="flex size-8 items-center justify-center rounded-md text-muted-foreground/60 transition-colors hover:bg-muted/50 hover:text-foreground"
          >
            <HugeiconsIcon
              icon={expanded ? ArrowShrink01Icon : ArrowExpand01Icon}
              size={14}
              strokeWidth={1.5}
            />
          </button>
        </div>

        {expanded && (
          <div className="animate-composer-slide mt-1.5 flex flex-col gap-1.5 sm:mt-3 sm:gap-2.5">
            {tasks.map((task, i) => (
              <div
                key={i}
                className={cn(
                  "flex items-start gap-2.5 text-xs leading-snug",
                  task.dimmed ? "text-muted-foreground/40" : "text-foreground"
                )}
              >
                <span
                  className={cn(
                    "mt-[3px] flex h-[14px] w-[14px] shrink-0 items-center justify-center rounded-full border",
                    task.dimmed
                      ? "border-muted-foreground/20"
                      : "border-muted-foreground/40"
                  )}
                />
                <span>
                  {i + 1}. {task.label}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </Island>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { HugeiconsIcon } from "@hugeicons/react"
import { Cancel01Icon, File01Icon, Image01Icon } from "@hugeicons/core-free-icons"
import type { ComposerFile } from "./composer"

const FILE_ICONS = {
  file: File01Icon,
  image: Image01Icon,
} as const

export function ComposerAttachments({
  files,
  onRemove,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  files: ComposerFile[]
  onRemove?: (name: string) => void
}) {
  if (files.length === 0) return null

  return (
    <div
      data-slot="composer-attachments"
      className={cn("animate-composer-slide flex gap-2 px-4 pt-3 pb-1", className)}
      {...props}
    >
      {files.map((file) => (
        <div
          key={file.name}
          className="group flex items-center gap-2 rounded-lg border border-border/60 bg-muted/40 px-3 py-2"
        >
          <HugeiconsIcon
            icon={FILE_ICONS[file.type]}
            size={14}
            strokeWidth={1.5}
            className="shrink-0 text-muted-foreground"
          />
          <div className="min-w-0">
            <p className="max-w-[140px] truncate text-xs font-medium">
              {file.name}
            </p>
            <p className="text-[10px] text-muted-foreground">{file.size}</p>
          </div>
          {onRemove && (
            <button
              type="button"
              onClick={() => onRemove(file.name)}
              aria-label={`Remove ${file.name}`}
              className="ml-0.5 text-muted-foreground/50 transition-colors hover:text-foreground"
            >
              <HugeiconsIcon icon={Cancel01Icon} size={12} strokeWidth={1.5} />
            </button>
          )}
        </div>
      ))}
    </div>
  )
}

"use client"

import * as React from "react"
import { cn } from "@/lib/utils"
import { useComposer } from "./composer"

export function ComposerSuggestions({
  items,
  onSelect,
  className,
  ...props
}: React.ComponentProps<"div"> & {
  items: string[]
  onSelect?: (suggestion: string) => void
}) {
  const {
    actions: { setValue },
    meta: { textareaRef },
  } = useComposer()
  const [flashChip, setFlashChip] = React.useState<string | null>(null)

  const handleClick = React.useCallback(
    (suggestion: string) => {
      setFlashChip(suggestion)
      setTimeout(() => {
        setValue(suggestion)
        setFlashChip(null)
        textareaRef.current?.focus()
        onSelect?.(suggestion)
      }, 250)
    },
    [setValue, textareaRef, onSelect]
  )

  if (items.length === 0) return null

  return (
    <div
      data-slot="composer-suggestions"
      className={cn(
        "animate-composer-slide mt-1.5 flex w-full gap-1 overflow-x-auto px-0.5 pb-0.5 [-ms-overflow-style:none] [scrollbar-width:none] sm:mt-3 sm:flex-wrap sm:justify-center sm:gap-1.5 sm:overflow-visible sm:px-0 sm:pb-0 [&::-webkit-scrollbar]:hidden",
        className
      )}
      {...props}
    >
      {items.map((s) => (
        <button
          key={s}
          type="button"
          data-compact-touch
          aria-label={`Use suggestion: ${s}`}
          onClick={() => handleClick(s)}
          className={cn(
            "min-h-6 shrink-0 whitespace-nowrap rounded-md border border-border/60 px-2 py-1 text-left text-[11px] leading-4 text-muted-foreground transition-colors duration-200 hover:border-border hover:bg-muted/40 hover:text-foreground sm:min-h-7 sm:px-2.5 sm:text-center sm:text-xs sm:leading-snug",
            flashChip === s ? "animate-composer-chip" : ""
          )}
        >
          {s}
        </button>
      ))}
    </div>
  )
}
